    let mut result: i64 = 0 - 1;
    while lo < hi {
        let mid: i64 = lo + (hi - lo) / 2;
        let val: i64 = vec_get(arr, mid);
        if val == target {
            result = mid;
            lo = hi;
            ()
        } else {
            if val < target {
                lo = mid + 1;
                ()
            } else {
                hi = mid;
                ()
            };
            ()
        };
        ()
    };
    result
};

